// TestScore_SupportedLanguage_StillWorks is a regression guard that ensures
// a Go unit with realistic evidence still produces meaningful scores.
func TestScore_SupportedLanguage_StillWorks(t *testing.T) {
	// Construct realistic evidence for a Go function
	ev := []domain.Evidence{
		evidence.CodeMetrics{TotalLines: 200, CodeLines: 150, Complexity: 15}.ToEvidence(),
		evidence.GitStats{CommitCount: 42, AuthorCount: 3, AgeDays: 180}.ToEvidence(),
		evidence.LintResult{Tool: "golangci-lint", ErrorCount: 0}.ToEvidence(),
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true})

	// A supported language should produce real scores
	avg := scores.WeightedAverage(nil)
	if avg <= 0 {
		t.Errorf("supported language (Go) weighted average = %f, want > 0", avg)
	}

	// At least some dimensions should be present
	if len(scores) == 0 {
		t.Error("supported language (Go) should produce dimension scores, got none")
	}

	// Maintainability should be present (complexity=15 gives 0.80)
	if _, ok := scores[domain.DimMaintainability]; !ok {
		t.Error("complexity evidence should produce maintainability score")
	}
}

// TestScore_DefaultsNotInjected guards against the 0.5 default injection
// that was previously applied to unscored dimensions. Dimensions without
// evidence should be absent, and no score should equal 0.5 (the former default).
func TestScore_DefaultsNotInjected(t *testing.T) {
	// Only structural evidence — no code metrics, no git history
	ev := []domain.Evidence{
		{
			Kind:   domain.EvidenceKindStructural,
			Source: "structural",
			Passed: true,
			Metrics: map[string]float64{
				"global_mutable_count": 0,
			},
		},
	}

	scores := engine.Score(ev, policy.EvaluationResult{Passed: true})

	// No score should equal 0.5 (the former default injection value)
	for dim, score := range scores {
		if score == 0.5 {
			t.Errorf("dimension %s has score 0.5, the former default — default injection bug", dim)
		}
	}

	// Dimensions without evidence should be absent from the map.
	// With only global_mutable_count=0, we expect security to be set.
	// Check that only evidence-backed dimensions appear.
	if _, ok := scores[domain.DimSecurity]; !ok {
		t.Error("security should be present when global_mutable_count metric exists")
	}

	// These dimensions have no backing evidence and should be absent
	for _, dim := range []domain.Dimension{
		domain.DimMaintainability,
		domain.DimReadability,
		domain.DimOperationalQuality,
		domain.DimChangeRisk,
	} {
		if _, ok := scores[dim]; ok {
			t.Errorf("dimension %s should be absent (no backing evidence)", dim)
		}
	}
}

