// scoreDeepAnalysis handles new metrics from the analysis package:
// cognitive complexity, error wrapping, unsafe imports, hardcoded secrets.
func scoreDeepAnalysis(m map[string]float64, scores domain.DimensionScores) {
	// Cognitive complexity → readability (stronger signal than cyclomatic)
	if cogCplx, ok := m["cognitive_complexity"]; ok && cogCplx > 0 {
		switch {
		case cogCplx <= 8:
			setMax(scores, domain.DimReadability, 0.95)
		case cogCplx <= 15:
			setMax(scores, domain.DimReadability, 0.85)
		case cogCplx <= 25:
			// neutral — don't override if already set
		default:
			setMin(scores, domain.DimReadability, 0.50)
		}
	}

	// Error wrapping → operational_quality
	if unwrapped, ok := m["errors_not_wrapped"]; ok {
		if unwrapped == 0 {
			setMax(scores, domain.DimOperationalQuality, 0.90)
		} else if unwrapped <= 2 {
			setMax(scores, domain.DimOperationalQuality, 0.75)
		} else {
			setMin(scores, domain.DimOperationalQuality, 0.55)
		}
	}

	// Unsafe imports → security
	if unsafeCount, ok := m["unsafe_import_count"]; ok && unsafeCount > 0 {
		setMin(scores, domain.DimSecurity, 0.60)
	}

	// Hardcoded secrets → security (critical)
	if secrets, ok := m["hardcoded_secrets"]; ok && secrets > 0 {
		setMin(scores, domain.DimSecurity, 0.30)
	}

	// Empty catch blocks → correctness
	if empty, ok := m["empty_catch_blocks"]; ok && empty > 0 {
		setMin(scores, domain.DimCorrectness, 0.55)
	}

	// Quadratic patterns → performance_appropriateness
	if quads, ok := m["quadratic_patterns"]; ok && quads > 0 {
		setMin(scores, domain.DimPerformanceAppropriateness, 0.45)
	}

	// Nested loop pairs → performance_appropriateness (milder than quadratic)
	if nested, ok := m["nested_loop_pairs"]; ok && nested > 0 && m["quadratic_patterns"] == 0 {
		setMin(scores, domain.DimPerformanceAppropriateness, 0.60)
	}

	// High return count → maintainability (many exit points)
	if returns, ok := m["return_count"]; ok && returns > 5 {
		setMin(scores, domain.DimMaintainability, 0.65)
	}

	// Fan-in → change_risk (high fan-in = many callers, risky to change)
	if fanIn, ok := m["fan_in"]; ok {
		switch {
		case fanIn <= 5:
			setMax(scores, domain.DimChangeRisk, 0.95)
		case fanIn <= 10:
			setMax(scores, domain.DimChangeRisk, 0.85)
		case fanIn <= 20:
			setMax(scores, domain.DimChangeRisk, 0.70)
		default:
			setMin(scores, domain.DimChangeRisk, 0.50)
		}
	}

	// Fan-out → maintainability (high fan-out = too many dependencies)
	if fanOut, ok := m["fan_out"]; ok {
		switch {
		case fanOut <= 5:
			setMax(scores, domain.DimMaintainability, 0.95)
		case fanOut <= 10:
			setMax(scores, domain.DimMaintainability, 0.85)
		case fanOut <= 15:
			setMax(scores, domain.DimMaintainability, 0.70)
		default:
			setMin(scores, domain.DimMaintainability, 0.55)
		}
	}

	// Dead code → maintainability (unused exports are maintenance burden)
	if deadCode, ok := m["is_dead_code"]; ok && deadCode > 0 {
		setMin(scores, domain.DimMaintainability, 0.60)
	}

	// Dep depth → architectural_fitness
	if depth, ok := m["dep_depth"]; ok {
		switch {
		case depth <= 3:
			setMax(scores, domain.DimArchitecturalFitness, 0.95)
		case depth <= 5:
			setMax(scores, domain.DimArchitecturalFitness, 0.85)
		case depth <= 8:
			setMax(scores, domain.DimArchitecturalFitness, 0.70)
		default:
			setMin(scores, domain.DimArchitecturalFitness, 0.55)
		}
	}

	// Instability for concrete packages → architectural_fitness
	if instability, ok := m["instability"]; ok && instability > 0.8 {
		// High instability is only bad for concrete implementations
		// (main packages naturally have instability = 1.0, that's fine)
		if m["is_dead_code"] == 0 && m["fan_in"] > 0 {
			setMin(scores, domain.DimArchitecturalFitness, 0.65)
		}
	}

	// Concrete deps → testability + arch_fitness
	if concreteDeps, ok := m["concrete_deps"]; ok && concreteDeps > 0 {
		setMin(scores, domain.DimTestability, 0.65)
		setMin(scores, domain.DimArchitecturalFitness, 0.65)
	}

	// Unused params → maintainability
	if unusedParams, ok := m["unused_params"]; ok && unusedParams > 0 {
		setMin(scores, domain.DimMaintainability, 0.70)
	}

	// Interface size → arch_fitness (Interface Segregation Principle)
	if ifaceSize, ok := m["interface_size"]; ok && ifaceSize > 10 {
		setMin(scores, domain.DimArchitecturalFitness, 0.60)
	}

	// Type-aware error wrapping (more precise than AST-only)
	if unwrapped, ok := m["type_aware_unwrapped"]; ok && unwrapped > 0 {
		setMin(scores, domain.DimOperationalQuality, 0.60)
	}
}

func scoreFromGitHistory(e domain.Evidence, scores domain.DimensionScores) {
	authors := metricOrSummaryInt(e, "author_count", "author")
	switch {
	case authors >= 3:
		setMax(scores, domain.DimChangeRisk, 0.95)
	case authors >= 2:
		setMax(scores, domain.DimChangeRisk, 0.90)
	case authors == 1:
		setMax(scores, domain.DimChangeRisk, 0.70)
	}

	commits := metricOrSummaryInt(e, "commit_count", "commit")
	switch {
	case commits > 50:
		setMax(scores, domain.DimOperationalQuality, 0.95)
	case commits > 20:
		setMax(scores, domain.DimOperationalQuality, 0.90)
	case commits > 10:
		setMax(scores, domain.DimOperationalQuality, 0.85)
	case commits > 0:
		setMax(scores, domain.DimOperationalQuality, 0.75)
	}
}

// metricOrSummaryInt returns an int metric from e.Metrics[metricKey], falling back to
// extractSummaryInt(e.Summary, summaryKeyword) for backward compatibility.
func metricOrSummaryInt(e domain.Evidence, metricKey, summaryKeyword string) int {
	if e.Metrics != nil {
		if v, ok := e.Metrics[metricKey]; ok {
			return int(v)
		}
	}
	return extractSummaryInt(e.Summary, summaryKeyword)
}

// metricOrSummaryFloat returns a float metric from e.Metrics[metricKey], falling back to
// extractSummaryFloat(e.Summary, summaryKeyword) for backward compatibility.
func metricOrSummaryFloat(e domain.Evidence, metricKey, summaryKeyword string) float64 {
	if e.Metrics != nil {
		if v, ok := e.Metrics[metricKey]; ok {
			return v
		}
	}
	return extractSummaryFloat(e.Summary, summaryKeyword)
}

// extractSummaryInt pulls an integer near a keyword in a summary string.
// Handles both "42 code" (number before keyword) and "complexity 2" (number after keyword).
func extractSummaryInt(summary, keyword string) int {
	idx := strings.Index(summary, keyword)
	if idx < 0 {
		return -1
	}

	// Try number AFTER keyword (e.g., "complexity 2")
	after := strings.TrimSpace(summary[idx+len(keyword):])
	var n int
	if _, err := fmt.Sscanf(after, "%d", &n); err == nil {
		return n
	}

	// Try number BEFORE keyword (e.g., "42 code")
	if idx > 0 {
		sub := strings.TrimSpace(summary[:idx])
		for i := len(sub) - 1; i >= 0; i-- {
			if sub[i] == ' ' || sub[i] == '(' || sub[i] == ',' {
				if _, err := fmt.Sscanf(strings.TrimSpace(sub[i+1:]), "%d", &n); err == nil {
					return n
				}
				break
			}
			if i == 0 {
				if _, err := fmt.Sscanf(strings.TrimSpace(sub), "%d", &n); err == nil {
					return n
				}
			}
		}
	}
	return -1
}

// extractSummaryFloat pulls a float before a keyword.
func extractSummaryFloat(summary, keyword string) float64 {
	idx := strings.Index(summary, keyword)
	if idx <= 0 {
		return -1
	}
	sub := strings.TrimSpace(summary[:idx])
	for i := len(sub) - 1; i >= 0; i-- {
		if sub[i] == ' ' || sub[i] == '(' || sub[i] == ',' {
			var f float64
			if _, err := fmt.Sscanf(strings.TrimSpace(sub[i+1:]), "%f", &f); err == nil {
				return f
			}
			break
		}
	}
	return -1
}

func severityPenalty(s domain.Severity) float64 {
	switch s {
	case domain.SeverityCritical:
		return 0.5
	case domain.SeverityError:
		return 0.3
	case domain.SeverityWarning:
		return 0.1
	default:
		return 0.05
	}
}

// StatusFromScore determines certification status from a weighted score.
func StatusFromScore(score float64, hasBlockingViolations bool) domain.Status {
	if hasBlockingViolations {
		return domain.StatusProbationary
	}

	switch {
	case score >= 0.80:
		return domain.StatusCertified
	case score >= 0.60:
		return domain.StatusCertifiedWithObservations
	case score >= 0.40:
		return domain.StatusProbationary
	default:
		return domain.StatusDecertified
	}
}

